+const used = new Set<string>();
+export function addRefreshGraph(graph) {
+  const request = graph.state(null, { name: 'refresh.request' });
+  const validate = graph.derived([request], (token) => token, { name: 'refresh.validate' });
+  const rotate = graph.derived([validate], (token) => token, { name: 'refresh.rotate' });
+  graph.effect([rotate], () => undefined, { name: 'session.persist.refresh', meta: { capability: 'session-mutation', mode: 'online' } });
+}
+export function refresh(token: string) {
+  if (used.has(token)) throw new Error('replay');
+  used.add(token);
+  return { token: token + '-rotated', familyId: 'family-1' };
+}
